#include "controller.h"

#include <string.h>

#define CONTROLLER_FILL_LEVEL_THRESHOLD 60
#define CONTROLLER_MIN_HEATING_LEVEL 55
#define CONTROLLER_LEVEL_HIGH_THRESHOLD 75
#define CONTROLLER_TEMP_LOW_THRESHOLD 45
#define CONTROLLER_TEMP_EARLY_OFF_THRESHOLD 47
#define CONTROLLER_TEMP_HIGH_THRESHOLD 48
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

static void controller_set_safe_idle(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

static bool controller_check_timeout(controller_t *controller, uint32_t now_ms)
{
    if (controller == NULL) {
        return false;
    }

    bool level_stale = false;
    bool temp_stale = false;

    if (controller->has_valid_level &&
        (now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        level_stale = true;
    }

    if (controller->has_valid_temperature &&
        (now_ms - controller->last_temperature_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        temp_stale = true;
    }

    return level_stale || temp_stale;
}

static void controller_apply_timeout(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }
    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->has_valid_level = false;
}

static void controller_update_state(controller_t *controller, int level, int temperature_c, uint32_t now_ms)
{
    if (controller == NULL) {
        return;
    }

    /* Timeout handling - go to safe idle */
    if (controller_check_timeout(controller, now_ms)) {
        controller_apply_timeout(controller);
        return;
    }

    /* Default: keep current state if no change needed */
    bool needs_change = false;

    /* Safety constraint: if level < 55, heater must be off */
    if (level < CONTROLLER_MIN_HEATING_LEVEL) {
        controller->heater_on = false;
        needs_change = true;
    }

    /* Low level (< 60): open inlet, heater off */
    if (level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
        controller->inlet_open = true;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_FILLING;
        needs_change = true;
    }

    /* High level (> 75): close inlet */
    else if (level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
        controller->inlet_open = false;
        needs_change = true;
    }

    /* Safe fill region: 60 <= level <= 75 */
    else {
        /* Heater guard: heater only on if level >= 55 (already checked above, but double-check) */
        controller->heater_on = false;

        if (temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* Safe to heat: close inlet and turn heater on */
            controller->inlet_open = false;
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
            needs_change = true;
        }
        else if (temperature_c < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
            /* 45 <= TEMP < 47: close inlet, hold heater state */
            controller->inlet_open = false;
            controller->state = CONTROLLER_STATE_HOLDING;
            needs_change = true;
        }
        else if (temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* 47 <= TEMP <= 48: check for rising temp */
            bool temp_rising = false;
            if (controller->has_valid_temperature && controller->previous_temperature_c < temperature_c) {
                temp_rising = true;
            }

            if (temp_rising) {
                /* Early heater off when temperature is rising in the target band */
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
                needs_change = true;
            }
            else {
                /* Not rising: hold previous safe heater state */
                /* If we were heating, keep it; otherwise stay off */
                if (controller->heater_on) {
                    controller->state = CONTROLLER_STATE_HOLDING;
                    needs_change = true;
                }
            }
        }
        else {
            /* TEMP > 48: close inlet and turn heater off */
            controller->inlet_open = false;
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
            needs_change = true;
        }
    }
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == NULL) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Handle sensor timeout and malformed input */
    switch (input.kind) {
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller_apply_timeout(controller);
        output.timed_out = true;
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        /* No input - check for timeout */
        if (controller_check_timeout(controller, input.now_ms)) {
            controller_apply_timeout(controller);
            output.timed_out = true;
        }
        break;
    }

    /* Handle valid sensor inputs */
    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;

        /* Update state based on current level and new temperature */
        if (controller->has_valid_level) {
            controller_update_state(controller, controller->last_level, input.temperature_c, input.now_ms);
        }
        break;

    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;

        /* Update state based on new level and current temperature */
        if (controller->has_valid_temperature) {
            controller_update_state(controller, input.level, controller->last_temperature_c, input.now_ms);
        }
        break;
    }

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

#!/usr/bin/env python3
"""
Self-tests for the Mixing Tank Fill-and-Heat Controller.

Each test corresponds to an acceptance criterion from docs/10_task.md:
- Boot leaves the inlet closed and the heater off.
- The controller stays in the safe all-off state until both temperature and level have been seen validly.
- A low level such as 50 commands INLET OPEN and HEATER OFF.
- A safe level with low temperature such as LEVEL 65, TEMP 40 commands INLET CLOSED and HEATER ON.
- If LEVEL < 55, the heater remains off even when temperature is low.
- Near the upper band, rising temperature data causes an early ACT HEATER OFF.
- Malformed input or stale sensor data for more than 1000 ms forces INLET CLOSED and HEATER OFF.
- Closed-loop tests keep the vessel at or below 51 C.
"""

import unittest
from typing import List, Dict, Any


class TestControllerUnit(unittest.TestCase):
    """Unit tests for the controller logic."""

    def test_boot_leaves_inlet_closed_and_heater_off(self) -> None:
        """Boot leaves the inlet closed and the heater off."""
        from components.controller.controller import controller_init, controller_step, CONTROLLER_INPUT_NONE

        controller = {}  # type: ignore
        controller_init(controller)

        output = controller_step(controller, {"kind": CONTROLLER_INPUT_NONE, "temperature_c": 0, "level": 0, "now_ms": 0})

        self.assertFalse(output["inlet_open"], "Inlet should be closed on boot")
        self.assertFalse(output["heater_on"], "Heater should be off on boot")
        self.assertEqual(output["state"], "STATE SAFE_IDLE", "Should be in SAFE_IDLE state on boot")

    def test_stays_safe_until_both_sensors_seen(self) -> None:
        """The controller stays in the safe all-off state until both temperature and level have been seen validly."""
        from components.controller.controller import (
            controller_init,
            controller_step,
            CONTROLLER_INPUT_LEVEL,
            CONTROLLER_INPUT_TEMPERATURE,
        )

        controller = {}  # type: ignore
        controller_init(controller)

        # Level only - should stay safe
        output = controller_step(
            controller,
            {"kind": CONTROLLER_INPUT_LEVEL, "temperature_c": 0, "level": 50, "now_ms": 100}
        )
        self.assertFalse(output["heater_on"], "Heater should be off with only level seen")

        # Temp only - should stay safe
        output = controller_step(
            controller,
            {"kind": CONTROLLER_INPUT_TEMPERATURE, "temperature_c": 40, "level": 50, "now_ms": 200}
        )
        self.assertFalse(output["heater_on"], "Heater should be off with only temp seen")

        # Both - now can enter control logic
        output = controller_step(
            controller,
            {"kind": CONTROLLER_INPUT_LEVEL, "temperature_c": 40, "level": 50, "now_ms": 300}
        )
        self.assertFalse(output["heater_on"], "Heater should be off at level 50 (too low)")

    def test_low_level_commands_inlet_open_and_heater_off(self) -> None:
        """A low level such as 50 commands INLET OPEN and HEATER OFF."""
        from components.controller.controller import (
            controller_init,
            controller_step,
            CONTROLLER_INPUT_LEVEL,
            CONTROLLER_INPUT_TEMPERATURE,
        )

        controller = {}  # type: ignore
        controller_init(controller)

        # Send both sensors at low level
        output = controller_step(
            controller,
            {
                "kind": CONTROLLER_INPUT_LEVEL,
                "temperature_c": 40,
                "level": 50,
                "now_ms": 100
            }
        )

        self.assertTrue(output["inlet_open"], "Inlet should be OPEN at level 50")
        self.assertFalse(output["heater_on"], "Heater should be OFF at level 50")
        self.assertEqual(output["state"], "STATE FILLING", "Should be in FILLING state")

    def test_safe_level_with_low_temp_commands_inlet_closed_and_heater_on(self) -> None:
        """A safe level with low temperature such as LEVEL 65, TEMP 40 commands INLET CLOSED and HEATER ON."""
        from components.controller.controller import (
            controller_init,
            controller_step,
            CONTROLLER_INPUT_LEVEL,
            CONTROLLER_INPUT_TEMPERATURE,
        )

        controller = {}  # type: ignore
        controller_init(controller)

        # Send level first in safe range
        output = controller_step(
            controller,
            {"kind": CONTROLLER_INPUT_LEVEL, "temperature_c": 0, "level": 65, "now_ms": 100}
        )

        # Then send temperature (low)
        output = controller_step(
            controller,
            {"kind": CONTROLLER_INPUT_TEMPERATURE, "temperature_c": 40, "level": 65, "now_ms": 200}
        )

        self.assertFalse(output["inlet_open"], "Inlet should be CLOSED at level 65")
        self.assertTrue(output["heater_on"], "Heater should be ON at level 65, temp 40")
        self.assertEqual(output["state"], "STATE HEATING", "Should be in HEATING state")

    def test_heater_off_when_level_below_55(self) -> None:
        """If LEVEL < 55, the heater remains off even when temperature is low."""
        from components.controller.controller import (
            controller_init,
            controller_step,
            CONTROLLER_INPUT_LEVEL,
            CONTROLLER_INPUT_TEMPERATURE,
        )

        controller = {}  # type: ignore
        controller_init(controller)

        # Send level below 55 with low temperature
        output = controller_step(
            controller,
            {"kind": CONTROLLER_INPUT_LEVEL, "temperature_c": 40, "level": 50, "now_ms": 100}
        )

        self.assertFalse(output["heater_on"], "Heater should be OFF when level < 55")
        self.assertEqual(output["state"], "STATE FILLING", "Should be in FILLING state")

    def test_rising_temp_in_47_48_band_causes_early_heater_off(self) -> None:
        """Near the upper band, rising temperature data causes an early ACT HEATER OFF."""
        from components.controller.controller import (
            controller_init,
            controller_step,
            CONTROLLER_INPUT_LEVEL,
            CONTROLLER_INPUT_TEMPERATURE,
        )

        controller = {}  # type: ignore
        controller_init(controller)

        # Send level in safe range
        output = controller_step(
            controller,
            {"kind": CONTROLLER_INPUT_LEVEL, "temperature_c": 0, "level": 65, "now_ms": 100}
        )

        # Send temp at 47 (in early off band)
        output = controller_step(
            controller,
            {"kind": CONTROLLER_INPUT_TEMPERATURE, "temperature_c": 47, "level": 65, "now_ms": 200}
        )
        self.assertTrue(output["heater_on"], "Heater should be ON at temp 47 (not rising yet)")

        # Send temp at 48 (still in band) - not rising from 47
        output = controller_step(
            controller,
            {"kind": CONTROLLER_INPUT_TEMPERATURE, "temperature_c": 48, "level": 65, "now_ms": 300}
        )
        self.assertTrue(output["heater_on"], "Heater should still be ON at temp 48 (not rising)")

        # Send temp rising from 47 to 48 - should turn off early
        output = controller_step(
            controller,
            {"kind": CONTROLLER_INPUT_TEMPERATURE, "temperature_c": 48, "level": 65, "now_ms": 400}
        )
        self.assertFalse(output["heater_on"], "Heater should be OFF when temp is rising from 47 to 48")

    def test_malformed_input_forces_safe_state(self) -> None:
        """Malformed input or stale sensor data for more than 1000 ms forces INLET CLOSED and HEATER OFF."""
        from components.controller.controller import (
            controller_init,
            controller_step,
            CONTROLLER_INPUT_SENSOR_TIMEOUT,
            CONTROLLER_INPUT_INVALID_TEMPERATURE,
            CONTROLLER_INPUT_INVALID_LEVEL,
        )

        controller = {}  # type: ignore
        controller_init(controller)

        # First get into a valid state
        output = controller_step(
            controller,
            {"kind": CONTROLLER_INPUT_LEVEL, "temperature_c": 0, "level": 65, "now_ms": 100}
        )
        self.assertFalse(output["inlet_open"], "Inlet should be CLOSED")

        # Then send sensor timeout - should go to safe state
        output = controller_step(
            controller,
            {"kind": CONTROLLER_INPUT_SENSOR_TIMEOUT, "temperature_c": 0, "level": 65, "now_ms": 200}
        )

        self.assertFalse(output["inlet_open"], "Inlet should be CLOSED after timeout")
        self.assertFalse(output["heater_on"], "Heater should be OFF after timeout")
        self.assertEqual(output["state"], "STATE SAFE_IDLE", "Should be in SAFE_IDLE state after timeout")

    def test_invalid_temp_forces_safe_state(self) -> None:
        """Invalid temperature input forces safe state."""
